Code.Terraform:
```hcl
resource "aws_sagemaker_model" "model" {
  name               = "<example_resource_name>"
  execution_role_arn = "<example_resource_id>"

  primary_container {
    image = "<example_resource_name>"
  }

  # 重要: VPC構成によりモデルのVPCネットワーキングが有効になっているため、このチェックは合格します
  vpc_config {
    subnets            = ["<example_resource_id>"]       # 重大な
    security_group_ids = ["<example_resource_id>"]       # 重大な
  }
}
```
